def is_prime(number):
    if number < 2:
        return False

    for i in range(2, int(number ** 0.5) + 1):
        if number % i == 0:
            return False
    return True


print("1-50 arasindaki asal sayilar:")
primes = [n for n in range(1, 51) if is_prime(n)]
print(primes)
print("\nToplam asal sayi adedi:", len(primes))

# Tekil kontrol
test_numbers = [97, 100, 113, 1]
for num in test_numbers:
    print(f"\n{num} asal mi: {is_prime(num)}")

# Eratosthenes kalburu (sieve) ile daha hizli yontem
def sieve_of_eratosthenes(limit):
    is_prime_list = [True] * (limit + 1)
    is_prime_list[0] = is_prime_list[1] = False

    for i in range(2, int(limit ** 0.5) + 1):
        if is_prime_list[i]:
            for j in range(i * i, limit + 1, i):
                is_prime_list[j] = False

    return [i for i, prime in enumerate(is_prime_list) if prime]


print("\nEratosthenes kalburu ile 1-30 arasi asallar:")
print(sieve_of_eratosthenes(30))
